// // This module implements an 8-bit register that loads data on the falling edge of the clock and does not reset asynchronously.
module reg_8bit(
    input clk, 
    input reset, 
    input load, 
    input [7:0] d, 
    output reg [7:0] q);

    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 8'b0;
        else if (load)
            q <= d;
    end
endmodule
